const zlib = require("zlib");
const fs = require("fs");

function tryDecompressWithOffsets(hex) {
  const buffer = Buffer.from(hex, "hex");

  for (let offset = 0; offset < 12; offset++) {
    try {
      const slice = buffer.slice(offset);
      const result = zlib.inflateSync(slice);
      //or inflateRawSync(slice)
      console.log("SUCCESS at offset:", offset);
      return result;
    } catch (e) {
      // ignore and continue
    }
  }

  throw new Error("Could not decompress at any tested offset");
}

(async () => {
  try {
    const hexInput =
      ""; // example zlib-compressed hex
    const decompressed = tryDecompressWithOffsets(hexInput);

    console.log("Decompressed (hex):", decompressed.toString("hex"));
    fs.writeFileSync("decompreSSed.txt", decompressed.toString("hex"));
    //console.log("Decompressed (utf8):", decompressed.toString());
  } catch (err) {
    console.error(err.message);
  }
})();
